def _get_popen_kwargs(self, subprocess: t.Any) -> dict[str, t.Any]:
    kwargs: dict[str, t.Any] = {}

    if WIN and self.process_priority is not None:
        class_name = _WINDOWS_PRIORITY_CLASSES.get(self.process_priority)
        priority_class = getattr(subprocess, class_name, None)

        if priority_class is not None:
            kwargs["creationflags"] = priority_class

    return kwargs

def _apply_unix_priority(self, pid: int) -> None:
    if WIN or self.process_priority is None:
        return

    niceness = _UNIX_PROCESS_PRIORITIES.get(self.process_priority)

    if niceness is None:
        return

    try:
        os.setpriority(os.PRIO_PROCESS, pid, niceness)  # type: ignore[attr-defined]
    except (AttributeError, OSError, PermissionError):
        # Not supported on this platform, or insufficient permissions
        # to raise the priority. Fall back to the default priority.
        pass

